mapper.select:
SELECT DISTINCT A.MENU_ID , A.MENU_NM , A.UP_MENU_ID , A.ROUTER_NM , A.MENU_NM_ENG , A.ROUTER_PATH , A.VIEW_PATH , A.MENU_ICON , A.MENU_ODR , A.PARAM , A.COMP_ID , A.HR_ID FROM ESG.TB_SYS_MENU_FAVORITES A WHERE A.COMP_ID = #{compId} AND A.HR_ID = #{hrId}
UNION ALL
SELECT 'F001' as MENU_ID , 'My HSE 업무' as MENU_NM , '' as UP_MENU_ID , '' as ROUTER_NM , '' as MENU_NM_ENG , '' as ROUTER_PATH , '' as VIEW_PATH , '' as MENU_ICON , 1 as MENU_ODR , '' as PARAM , '' as COMP_ID , '' as HR_ID
WHERE NOT EXISTS ( SELECT 1 FROM ESG.TB_SYS_MENU_FAVORITES A WHERE A.COMP_ID = #{compId} AND A.HR_ID = #{hrId} ) ORDER BY MENU_ODR;
